INSERT INTO products (product_code, product_name, supplier, unit, price_ex_gst, notes)
SELECT d.product_code, d.product_name, d.supplier, d.unit, d.price_ex_gst, d.notes
FROM data d
WHERE NOT EXISTS (
    SELECT 1
    FROM products p
    WHERE p.product_code = d.product_code
);

SELECT supplier, COUNT(*) AS product_count
FROM products
WHERE supplier IN ('Haymes', 'Taubmans')
GROUP BY supplier
ORDER BY supplier;
